//Text constants
//Funny chars:<br>•&nbsp;🔒
function automakers(makers,header="") {
    const autoString = ['<div class=\"automakers ','\"></div>'];
    var autoResult = "";
    if (!Array.isArray(makers))return;//it must be an array argument
    for(let maker in makers){
        autoResult += autoString[0] + makers[maker] + autoString[1];
    }
    return header+autoResult;
}
